@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap');

:root {
    --primary: #fd9832;
    --primary-dark: #e48020;
    --secondary: #343399;
    --secondary-dark: #292980;
    --primary-light: rgba(253, 152, 50, 0.15);
    --secondary-light: rgba(52, 51, 153, 0.15);
    --white: #ffffff;
    --light-gray: #f5f7fa;
    --dark-gray: #333333;
    --medium-gray: #6c757d;
    --success: #28a745;
    --danger: #dc3545;
}

.petroleum-dashboard {
    font-family: 'Poppins', sans-serif;
    max-width: 1200px;
    margin: 0 auto;
    padding: 30px;
    background-color: var(--white);
    border-radius: 10px;
    box-shadow: 0 0 25px rgba(0, 0, 0, 0.05);
    color: var(--dark-gray);
}

.dashboard-header {
    text-align: center;
    margin-bottom: 30px;
    padding-bottom: 20px;
    border-bottom: 1px solid var(--light-gray);
}

.dashboard-header strong {
    font-size: 32px;
    color: var(--secondary);
    display: block;
    margin-bottom: 10px;
    font-weight: 600;
}

.dashboard-header p {
    font-size: 16px;
    color: var(--medium-gray);
    max-width: 800px;
    margin: 0 auto;
    line-height: 1.6;
}

.key-fact {
    display: flex;
    align-items: center;
    background-color: var(--secondary-light);
    padding: 20px;
    border-radius: 8px;
    margin-bottom: 30px;
}

.key-fact .icon {
    font-size: 28px;
    color: var(--secondary);
    margin-right: 15px;
}

.key-fact .fact-content {
    font-size: 16px;
    line-height: 1.5;
}

.key-fact .fact-content strong {
    color: var(--secondary);
    font-weight: 600;
}

.disbursement-container {
    margin-bottom: 30px;
}

.disbursement-header {
    margin-bottom: 20px;
}

.disbursement-header strong {
    font-size: 24px;
    color: var(--dark-gray);
    font-weight: 600;
}

/* New KPI Dashboard Style */
.kpi-dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(270px, 1fr));
    gap: 20px;
}

.kpi-card {
    background-color: var(--white);
    border-radius: 10px;
    padding: 20px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.08);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
    display: flex;
    flex-direction: column;
    border-top: 4px solid var(--secondary);
}

.kpi-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.12);
}

.kpi-card.exceptional {
    border-top: 4px solid var(--primary);
}

.kpi-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 15px;
    padding-bottom: 15px;
    border-bottom: 1px solid var(--light-gray);
}

.kpi-title {
    flex-grow: 1;
}

.kpi-title strong {
    font-size: 18px;
    color: var(--dark-gray);
    font-weight: 600;
}

.kpi-icon {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background-color: var(--secondary-light);
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 18px;
    color: var(--secondary);
}

.exceptional .kpi-icon {
    background-color: var(--primary-light);
    color: var(--primary);
}

.kpi-primary-metric {
    text-align: center;
    margin-bottom: 20px;
    padding: 10px;
    border-radius: 6px;
    background-color: var(--light-gray);
}

.kpi-primary-metric .metric-label {
    font-size: 16px;
    color: var(--medium-gray);
    margin-bottom: 5px;
}

.kpi-primary-metric .metric-value {
    font-size: 32px;
    font-weight: 700;
    color: var(--secondary);
}

.exceptional .kpi-primary-metric .metric-value {
    color: var(--primary);
}

.kpi-secondary-metrics {
    display: flex;
    justify-content: space-between;
    margin-bottom: 15px;
}

.secondary-metric {
    flex-basis: 48%;
    text-align: center;
}

.secondary-metric .metric-value {
    font-size: 18px;
    font-weight: 600;
    margin-bottom: 5px;
}

.secondary-metric .metric-label {
    font-size: 16px;
    color: var(--medium-gray);
}

.secondary-metric.trend.up .metric-value {
    color: var(--success);
}

.secondary-metric.trend.down .metric-value {
    color: var(--danger);
}

.secondary-metric.split {
    display: flex;
    justify-content: space-between;
}

.split-item {
    flex-basis: 48%;
    text-align: center;
}

.split-value {
    font-size: 18px;
    font-weight: 600;
}

.split-label {
    font-size: 16px;
    color: var(--medium-gray);
}

.kpi-info {
    font-size: 16px;
    color: var(--medium-gray);
    margin-top: auto;
    padding-top: 15px;
    border-top: 1px solid var(--light-gray);
    line-height: 1.5;
}

.dashboard-footer {
    padding-top: 30px;
}

.kpi-row {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    margin-bottom: 25px;
    background-color: var(--secondary);
    border-radius: 8px;
    padding: 20px;
}

.kpi-item {
    text-align: center;
    flex: 1;
    min-width: 120px;
    padding: 0 15px;
    border-right: 1px solid rgba(255, 255, 255, 0.2);
}

.kpi-item:last-child {
    border-right: none;
}

.kpi-value {
    font-size: 26px;
    font-weight: 700;
    color: var(--white);
    margin-bottom: 5px;
}

.kpi-label {
    font-size: 16px;
    color: rgba(255, 255, 255, 0.8);
}

.note {
    text-align: center;
    color: var(--medium-gray);
    font-size: 16px;
    font-style: italic;
    line-height: 1.5;
}

@media (max-width: 768px) {
    .petroleum-dashboard {
        padding: 20px 15px;
    }

    .kpi-dashboard-grid {
        grid-template-columns: 1fr;
    }

    .kpi-row {
        flex-direction: column;
    }

    .kpi-item {
        margin-bottom: 15px;
        padding-bottom: 15px;
        border-right: none;
        border-bottom: 1px solid rgba(255, 255, 255, 0.2);
    }

    .kpi-item:last-child {
        margin-bottom: 0;
        padding-bottom: 0;
        border-bottom: none;
    }
}


