@import url('https://fonts.googleapis.com/css2?family=Poppins:wght@300;400;500;600;700&display=swap');

:root {
    --primary: #fd9832;
    --primary-dark: #e48020;
    --primary-light: rgba(253, 152, 50, 0.15);
    --secondary: #343399;
    --secondary-dark: #292980;
    --secondary-light: rgba(52, 51, 153, 0.15);
    --white: #ffffff;
    --light-gray: #f5f7fa;
    --dark-gray: #333333;
    --medium-gray: #6c757d;
    --success: #28a745;
    --danger: #dc3545;
    --chart-color-1: #343399;
    --chart-color-2: #fd9832;
    --chart-color-3: #4BC0C0;
    --chart-color-4: #9966FF;
}

.petroleum-dashboard {
    font-family: 'Poppins', sans-serif;
    max-width: 1200px;
    margin: 0 auto;
    padding: 30px;
    background-color: var(--white);
    border-radius: 10px;
    box-shadow: 0 0 25px rgba(0, 0, 0, 0.05);
    color: var(--dark-gray);
}

.dashboard-header {
    text-align: center;
    margin-bottom: 30px;
    padding-bottom: 20px;
    border-bottom: 1px solid var(--light-gray);
}

.dashboard-header strong {
    font-size: 32px;
    color: var(--secondary);
    display: block;
    margin-bottom: 10px;
    font-weight: 600;
}

.dashboard-header p {
    font-size: 16px;
    color: var(--medium-gray);
    max-width: 800px;
    margin: 0 auto;
    line-height: 1.6;
}

.key-fact {
    display: flex;
    align-items: center;
    background-color: var(--secondary-light);
    padding: 20px;
    border-radius: 8px;
    margin-bottom: 30px;
}

.fact-content {
    font-size: 16px;
    line-height: 1.5;
}

.fact-content strong {
    color: var(--secondary);
    font-weight: 600;
}

/* Dashboard Filters */
.dashboard-filters {
    display: flex;
    align-items: center;
    margin-bottom: 30px;
    padding: 15px;
    background-color: var(--light-gray);
    border-radius: 8px;
}

.filter-label {
    margin-right: 15px;
    font-size: 16px;
}

.filter-controls {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    flex-grow: 1;
}

.filter-select {
    padding: 10px 15px;
    border: 1px solid var(--medium-gray);
    border-radius: 5px;
    font-family: 'Poppins', sans-serif;
    font-size: 16px;
    color: var(--dark-gray);
    min-width: 170px;
    background-color: var(--white);
    cursor: pointer;
    transition: border-color 0.3s ease;
}

.filter-select:hover, .filter-select:focus {
    border-color: var(--secondary);
    outline: none;
}

/* KPI Summary Cards */
.kpi-summary-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
}

.kpi-summary-card {
    display: flex;
    align-items: center;
    background-color: var(--white);
    border-radius: 10px;
    padding: 20px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.08);
    border-left: 4px solid var(--secondary);
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.kpi-summary-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.12);
}

.kpi-card-content {
    flex-grow: 1;
}

.kpi-card-title {
    font-size: 16px;
    color: var(--medium-gray);
    margin-bottom: 5px;
}

.kpi-card-value {
    font-size: 26px;
    font-weight: 700;
    color: var(--dark-gray);
    margin-bottom: 5px;
}

.kpi-card-subtext {
    font-size: 16px;
    color: var(--medium-gray);
    margin-bottom: 5px;
}

.kpi-card-trend {
    font-size: 16px;
    font-weight: 500;
    position: relative;
    padding-left: 20px;
}

.kpi-card-trend.up {
    color: var(--success);
}

.kpi-card-trend.up::before {
    content: "▲";
    position: absolute;
    left: 0;
    top: 2px;
    font-size: 12px;
}

.kpi-card-trend.down {
    color: var(--danger);
}

.kpi-card-trend.down::before {
    content: "▼";
    position: absolute;
    left: 0;
    top: 2px;
    font-size: 12px;
}

/* Charts Container */
.charts-container {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(450px, 1fr));
    gap: 20px;
    margin-bottom: 30px;
}

.chart-wrapper {
    background-color: var(--white);
    border-radius: 10px;
    padding: 20px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.08);
    transition: transform 0.3s ease;
}

.chart-wrapper:hover {
    transform: translateY(-5px);
}

.chart-wrapper.full-width {
    grid-column: 1 / -1;
}

.chart-title {
    font-size: 18px;
    font-weight: 600;
    color: var(--dark-gray);
    margin-bottom: 15px;
    text-align: center;
}

/* CSS-only Pie Chart with Animation */
.css-pie-chart {
    display: flex;
    justify-content: center;
    align-items: center;
    margin: 20px 0;
}

.pie-container {
    position: relative;
    width: 200px;
    height: 200px;
    border-radius: 50%;
    overflow: hidden;
    box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
}

.pie-slice {
    position: absolute;
    width: 100%;
    height: 100%;
    transform-origin: center;
    opacity: 0;
    transition: opacity 1s ease;
}

.animate-in .pie-slice {
    opacity: 1;
}

.slice-70 {
    background-color: var(--secondary);
    clip-path: polygon(50% 50%, 50% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 0%, 50% 0%);
    transform: rotate(0deg);
    transition-delay: 0.1s;
}

.slice-15 {
    background-color: var(--primary);
    clip-path: polygon(50% 50%, 100% 0%, 100% 50%);
    transform: rotate(252deg);
    transition-delay: 0.2s;
}

.slice-10-5 {
    background-color: var(--chart-color-3);
    clip-path: polygon(50% 50%, 100% 0%, 100% 30%);
    transform: rotate(306deg);
    transition-delay: 0.3s;
}

.slice-4-5 {
    background-color: var(--chart-color-4);
    clip-path: polygon(50% 50%, 100% 0%, 100% 16%);
    transform: rotate(344deg);
    transition-delay: 0.4s;
}

.pie-center {
    position: absolute;
    width: 100px;
    height: 100px;
    background-color: white;
    border-radius: 50%;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    color: var(--dark-gray);
    font-size: 18px;
    box-shadow: 0 1px 5px rgba(0, 0, 0, 0.1);
}

/* CSS-only Bar Chart with Animation */
.css-bar-chart {
    position: relative;
    height: 300px;
    margin: 20px 0 40px;
}

.chart-grid {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 30px;
    background: 
        repeating-linear-gradient(to bottom, transparent, transparent 59px, rgba(0,0,0,0.05) 59px, rgba(0,0,0,0.05) 60px);
    background-size: 60px 60px;
    z-index: 1;
}

.bar-container {
    position: relative;
    display: flex;
    justify-content: space-around;
    height: 100%;
    z-index: 2;
}

.year-column {
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 18%;
}

.bar-stack {
    display: flex;
    flex-direction: column-reverse;
    width: 80%;
    height: 85%;
}

.bar-segment {
    width: 100%;
    border-top-left-radius: 4px;
    border-top-right-radius: 4px;
    transition: transform 0.8s cubic-bezier(0.34, 1.56, 0.64, 1);
    transform: scaleY(0);
    transform-origin: bottom;
}

.animate-in .bar-segment {
    transform: scaleY(1);
}

.bar-segment.abfa {
    background-color: var(--secondary);
    transition-delay: 0.1s;
}

.bar-segment.gnpc {
    background-color: var(--primary);
    transition-delay: 0.2s;
}

.bar-segment.gpf {
    background-color: var(--chart-color-3);
    transition-delay: 0.3s;
}

.year-label {
    margin-top: 10px;
    font-size: 16px;
    font-weight: 500;
}

/* CSS-only Horizontal Bar Chart with Animation */
.css-horizontal-bar-chart {
    margin: 20px 0;
}

.horizontal-bar-container {
    display: flex;
    flex-direction: column;
    gap: 15px;
}

.horizontal-bar-row {
    display: flex;
    align-items: center;
}

.horizontal-bar-label {
    width: 120px;
    font-size: 16px;
    font-weight: 500;
}

.horizontal-bar-wrapper {
    flex-grow: 1;
    height: 30px;
    background-color: var(--light-gray);
    border-radius: 5px;
    overflow: hidden;
    margin: 0 15px;
}

.horizontal-bar-segment {
    height: 100%;
    border-radius: 5px 0 0 5px;
    transform-origin: left;
}

.animate-width {
    animation: grow-width 1.5s cubic-bezier(0.34, 1.56, 0.64, 1);
    animation-fill-mode: both;
}

@keyframes grow-width {
    0% { width: 0; }
    100% { width: attr(style width); }
}

.horizontal-bar-value {
    width: 60px;
    text-align: right;
    font-size: 16px;
    font-weight: 600;
}

/* Chart Legend */
.chart-legend {
    margin-top: 20px;
}

.legend-item {
    display: flex;
    align-items: center;
    margin-bottom: 8px;
}

.legend-color {
    width: 16px;
    height: 16px;
    border-radius: 3px;
    margin-right: 8px;
}

.legend-text {
    font-size: 16px;
    color: var(--dark-gray);
}

/* Detailed KPI Cards */
.disbursement-container, .abfa-container {
    margin-bottom: 30px;
}

.disbursement-header, .abfa-header {
    margin-bottom: 20px;
