}

.kpi-secondary-metrics {
    display: flex;
    justify-content: space-between;
    margin-bottom: 15px;
}

.secondary-metric {
    flex-basis: 48%;
    text-align: center;
}

.secondary-metric .metric-value {
    font-size: 18px;
    font-weight: 600;
    margin-bottom: 5px;
    position: relative;
}

.secondary-metric .metric-label {
    font-size: 16px;
    color: var(--medium-gray);
}

.secondary-metric.trend.up .metric-value {
    color: var(--success);
    padding-left: 20px;
}

.secondary-metric.trend.up .metric-value::before {
    content: "▲";
    position: absolute;
    left: 0;
    top: 3px;
    font-size: 12px;
}

.secondary-metric.trend.down .metric-value {
    color: var(--danger);
    padding-left: 20px;
}

.secondary-metric.trend.down .metric-value::before {
    content: "▼";
    position: absolute;
    left: 0;
    top: 3px;
    font-size: 12px;
}

.secondary-metric.split {
    display: flex;
    justify-content: space-between;
}

.split-item {
    flex-basis: 48%;
    text-align: center;
}

.split-value {
    font-size: 18px;
    font-weight: 600;
}

.split-label {
    font-size: 16px;
    color: var(--medium-gray);
}

.kpi-info {
    font-size: 16px;
    color: var(--medium-gray);
    margin-top: auto;
    padding-top: 15px;
    border-top: 1px solid var(--light-gray);
    line-height: 1.5;
}

/* Footer */
.dashboard-footer {
    padding-top: 30px;
}

.kpi-row {
    display: flex;
    flex-wrap: wrap;
    justify-content: space-between;
    margin-bottom: 25px;
    background-color: var(--secondary);
    border-radius: 8px;
    padding: 20px;
}

.kpi-item {
    text-align: center;
    flex: 1;
    min-width: 120px;
    padding: 0 15px;
    border-right: 1px solid rgba(255, 255, 255, 0.2);
}

.kpi-item:last-child {
    border-right: none;
}

.kpi-value {
    font-size: 26px;
    font-weight: 700;
    color: var(--white);
    margin-bottom: 5px;
}

.kpi-label {
    font-size: 16px;
    color: rgba(255, 255, 255, 0.8);
}

.note {
    text-align: center;
    color: var(--medium-gray);
    font-size: 16px;
    font-style: italic;
    line-height: 1.5;
}

/* Animations */
.animate-in {
    opacity: 0;
    transform: translateY(30px);
    animation: fade-in 0.6s ease forwards;
}

@keyframes fade-in {
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Tooltips */
.tooltip {
    position: relative;
    cursor: pointer;
}

.tooltip::after {
    content: attr(data-tooltip);
    position: absolute;
    bottom: 125%;
    left: 50%;
    transform: translateX(-50%);
    background-color: rgba(0, 0, 0, 0.8);
    color: white;
    padding: 8px 12px;
    border-radius: 4px;
    font-size: 14px;
    white-space: nowrap;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s, visibility 0.3s;
    z-index: 10;
    pointer-events: none;
    font-weight: normal;
}

.tooltip::before {
    content: "";
    position: absolute;
    bottom: 125%;
    left: 50%;
    transform: translateX(-50%) translateY(100%);
    border-width: 6px;
    border-style: solid;
    border-color: rgba(0, 0, 0, 0.8) transparent transparent transparent;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s, visibility 0.3s;
    z-index: 10;
    pointer-events: none;
}

.tooltip:hover::after, .tooltip:hover::before {
    opacity: 1;
    visibility: visible;
}

/* Avoid tooltip overflow on edges */
.tooltip:hover::after {
    white-space: normal;
    width: max-content;
    max-width: 250px;
    word-wrap: break-word;
}

/* Responsive Design */
@media (max-width: 768px) {
    .petroleum-dashboard {
        padding: 20px 15px;
    }

    .charts-container {
        grid-template-columns: 1fr;
    }

    .kpi-dashboard-grid {
        grid-template-columns: 1fr;
    }

    .kpi-row {
        flex-direction: column;
    }

    .kpi-item {
        margin-bottom: 15px;
        padding-bottom: 15px;
        border-right: none;
        border-bottom: 1px solid rgba(255, 255, 255, 0.2);
    }

    .kpi-item:last-child {
        margin-bottom: 0;
        padding-bottom: 0;
        border-bottom: none;
    }

    .dashboard-filters {
        flex-direction: column;
        align-items: flex-start;
    }

    .filter-label {
        margin-bottom: 10px;
    }

    .pie-container {
        width: 180px;
        height: 180px;
    }

    .pie-center {
        width: 90px;
        height: 90px;
    }

    .horizontal-bar-label {
        width: 100px;
    }

    .tooltip::after {
        width: 150px;
        left: 0;
        transform: none;
    }

    .tooltip::before {
        left: 10px;
        transform: translateY(100%);
    }
}

/* Fix horizontal bar animation */
.horizontal-bar-segment.animate-width {
    width: 0;
}

.animate-in .horizontal-bar-segment[style*="width: 67%"] {
    animation-delay: 0.1s;
    animation: grow-width-67 1.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.animate-in .horizontal-bar-segment[style*="width: 21%"] {
    animation-delay: 0.2s;
    animation: grow-width-21 1.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.animate-in .horizontal-bar-segment[style*="width: 8%"] {
    animation-delay: 0.3s;
    animation: grow-width-8 1.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

.animate-in .horizontal-bar-segment[style*="width: 2%"] {
    animation-delay: 0.4s;
    animation: grow-width-2 1.5s cubic-bezier(0.34, 1.56, 0.64, 1) forwards;
}

@keyframes grow-width-67 {
    from { width: 0; }
    to { width: 67%; }
}

@keyframes grow-width-21 {
    from { width: 0; }
    to { width: 21%; }
}

@keyframes grow-width-8 {
    from { width: 0; }
    to { width: 8%; }
}

@keyframes grow-width-2 {
    from { width: 0; }
    to { width: 2%; }
}
