/* Dashboard styles - more WordPress-friendly approach */
#oil-money-dashboard {
    --primary: #333399;
    --secondary: #ff9933;
    --primary-light: rgba(51, 51, 153, 0.1);
    --secondary-light: rgba(255, 153, 51, 0.1);
    --success: #4CAF50;
    --success-light: rgba(76, 175, 80, 0.1);
    --danger: #F44336;
    --text-dark: #333333;
    --text-light: #777777;
    --bg-light: #f5f8ff;
    --bg-white: #ffffff;
    --shadow: 0 4px 10px rgba(0,0,0,0.08);

    font-family: 'Poppins', sans-serif;
    background-color: var(--bg-light);
    color: var(--text-dark);
    font-size: 16px;
    line-height: 1.5;
    padding: 20px;
    max-width: 1400px;
    margin: 0 auto;
    border-radius: 8px;
}

/* Reset for dashboard elements */
#oil-money-dashboard * {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

/* Header area */
#oil-money-dashboard .dashboard-header {
    background-color: var(--primary);
    color: white;
    padding: 15px 20px;
    border-radius: 8px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 20px;
    box-shadow: var(--shadow);
    animation: fadeInDown 0.8s ease-out;
}

#oil-money-dashboard .dashboard-title {
    font-size: 24px;
    font-weight: 600;
}

#oil-money-dashboard .dashboard-period {
    font-size: 16px;
    background-color: rgba(255,255,255,0.2);
    padding: 5px 10px;
    border-radius: 20px;
}

/* KPI summary row */
#oil-money-dashboard .kpi-summary {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 15px;
    margin-bottom: 20px;
}

#oil-money-dashboard .kpi-card {
    background-color: var(--bg-white);
    border-radius: 8px;
    padding: 15px;
    box-shadow: var(--shadow);
    display: flex;
    align-items: center;
    transition: transform 0.3s, box-shadow 0.3s;
    position: relative;
    animation: fadeInUp 0.6s ease-out;
    animation-fill-mode: both;
}

#oil-money-dashboard .kpi-card:nth-child(1) { animation-delay: 0.1s; }
#oil-money-dashboard .kpi-card:nth-child(2) { animation-delay: 0.2s; }
#oil-money-dashboard .kpi-card:nth-child(3) { animation-delay: 0.3s; }
#oil-money-dashboard .kpi-card:nth-child(4) { animation-delay: 0.4s; }

#oil-money-dashboard .kpi-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 15px rgba(0,0,0,0.1);
}

#oil-money-dashboard .kpi-icon {
    width: 40px;
    height: 40px;
    background-color: var(--primary-light);
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 12px;
    flex-shrink: 0;
}

#oil-money-dashboard .kpi-icon i {
    color: var(--primary);
    font-size: 20px;
}

#oil-money-dashboard .kpi-content {
    flex: 1;
}

#oil-money-dashboard .kpi-value {
    font-size: 24px;
    font-weight: 700;
    color: var(--primary);
    line-height: 1.2;
}

#oil-money-dashboard .kpi-label {
    font-size: 14px;
    color: var(--text-light);
    white-space: nowrap;
}

#oil-money-dashboard .kpi-trend {
    font-size: 13px;
    font-weight: 500;
    margin-top: 5px;
    display: inline-block;
    padding: 2px 6px;
    border-radius: 4px;
}

#oil-money-dashboard .trend-up {
    color: var(--success);
    background-color: rgba(76, 175, 80, 0.1);
}

#oil-money-dashboard .trend-down {
    color: var(--danger);
    background-color: rgba(244, 67, 54, 0.1);
}

/* Tooltips for KPI cards */
#oil-money-dashboard .kpi-tooltip,
#oil-money-dashboard .revenue-tooltip {
    position: absolute;
    top: 0;
    left: 50%;
    transform: translateX(-50%) translateY(-100%);
    background-color: var(--primary);
    color: white;
    padding: 12px;
    border-radius: 6px;
    width: 220px;
    z-index: 1000;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s, visibility 0.3s, transform 0.3s;
    box-shadow: 0 5px 15px rgba(0,0,0,0.15);
    pointer-events: none;
}

#oil-money-dashboard .kpi-tooltip:after,
#oil-money-dashboard .revenue-tooltip:after {
    content: "";
    position: absolute;
    top: 100%;
    left: 50%;
    transform: translateX(-50%);
    border-width: 8px;
    border-style: solid;
    border-color: var(--primary) transparent transparent transparent;
}

#oil-money-dashboard .kpi-card:hover .kpi-tooltip,
#oil-money-dashboard .revenue-card:hover .revenue-tooltip {
    opacity: 1;
    visibility: visible;
    transform: translateX(-50%) translateY(calc(-100% - 10px));
}

/* Two-column layout */
#oil-money-dashboard .dashboard-content {
    display: grid;
    grid-template-columns: 60% 40%;
    gap: 15px;
}

/* Chart panel */
#oil-money-dashboard .chart-panel {
    background-color: var(--bg-white);
    border-radius: 8px;
    padding: 15px;
    box-shadow: var(--shadow);
    margin-bottom: 15px;
    position: relative;
    animation: fadeIn 0.8s ease-out;
    animation-fill-mode: both;
}

#oil-money-dashboard .panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 15px;
}

#oil-money-dashboard .panel-title {
    font-size: 18px;
    font-weight: 600;
    color: var(--primary);
}

/* Revenue sources grid */
#oil-money-dashboard .revenue-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 15px;
}

/* Revenue Card */
#oil-money-dashboard .revenue-card {
    background-color: var(--bg-white);
    border-radius: 8px;
    padding: 15px;
    box-shadow: var(--shadow);
    display: flex;
    align-items: center;
    transition: transform 0.3s, box-shadow 0.3s;
    position: relative;
    animation: fadeInUp 0.6s ease-out;
    animation-fill-mode: both;
}

#oil-money-dashboard .revenue-card:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 15px rgba(0,0,0,0.1);
}

#oil-money-dashboard .revenue-tooltip {
    width: 240px;
}

#oil-money-dashboard .tooltip-title {
    font-size: 16px;
    font-weight: 600;
    margin-bottom: 5px;
}

#oil-money-dashboard .tooltip-text {
    font-size: 14px;
    line-height: 1.4;
}

#oil-money-dashboard .tooltip-highlight {
    color: var(--secondary);
    font-weight: 600;
}

/* Region breakdown */
#oil-money-dashboard .region-breakdown {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

#oil-money-dashboard .region-item {
    display: flex;
    flex-direction: column;
    gap: 10px;
}

#oil-money-dashboard .region-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

#oil-money-dashboard .region-info {
    display: flex;
    align-items: center;
}

#oil-money-dashboard .region-icon {
    width: 40px;
    height: 40px;
    border-radius: 8px;
    background-color: var(--primary-light);
    display: flex;
    align-items: center;
    justify-content: center;
    margin-right: 10px;
}

#oil-money-dashboard .region-icon i {
    color: var(--primary);
}

#oil-money-dashboard .region-icon.secondary {
    background-color: var(--secondary-light);
}

#oil-money-dashboard .region-icon.secondary i {
    color: var(--secondary);
}

#oil-money-dashboard .region-icon.success {
    background-color: var(--success-light);
}

#oil-money-dashboard .region-icon.success i {
    color: var(--success);
}

#oil-money-dashboard .region-details {
    display: flex;
    flex-direction: column;
}

#oil-money-dashboard .region-name {
    font-weight: 600;
    font-size: 14px;
}

#oil-money-dashboard .region-desc {
    color: var(--text-light);
    font-size: 13px;
}

#oil-money-dashboard .region-value {
    font-weight: 700;
    font-size: 18px;
    color: var(--primary);
}

#oil-money-dashboard .secondary-text {
    color: var(--secondary);
}

#oil-money-dashboard .success-text {
    color: var(--success);
}

#oil-money-dashboard .progress-bar {
    width: 100%;
    height: 8px;
    background-color: #f0f0f0;
    border-radius: 4px;
    overflow: hidden;
    position: relative;
}

#oil-money-dashboard .progress-fill {
    position: absolute;
    top: 0;
    left: 0;
    height: 100%;
    background-color: var(--primary);
    border-radius: 4px;
    animation: progressBar 1.5s ease-out forwards;
}

#oil-money-dashboard .secondary-fill {
    background-color: var(--secondary);
    animation-delay: 0.3s;
}

#oil-money-dashboard .success-fill {
    background-color: var(--success);
    animation-delay: 0.6s;
}

/* Animation Keyframes */
@keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 1; }
}

@keyframes fadeInUp {
    from { 
        opacity: 0;
        transform: translateY(20px);
    }
    to { 
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes fadeInDown {
    from { 
        opacity: 0;
        transform: translateY(-20px);
    }
    to { 
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes progressBar {
    0% { width: 0; }
    100% { width: 100%; }
}

/* Responsive adjustments */
@media (max-width: 1024px) {
    #oil-money-dashboard .kpi-summary {
        grid-template-columns: repeat(2, 1fr);
    }

    #oil-money-dashboard .dashboard-content {
        grid-template-columns: 1fr;
    }

    #oil-money-dashboard .revenue-grid {
        grid-template-columns: repeat(2, 1fr);
    }
}

@media (max-width: 640px) {
    #oil-money-dashboard .kpi-summary {
        grid-template-columns: 1fr;
    }

    #oil-money-dashboard .revenue-grid {
        grid-template-columns: 1fr;
    }

    #oil-money-dashboard .dashboard-header {
        flex-direction: column;
        align-items: flex-start;
    }

    #oil-money-dashboard .dashboard-period {
        margin-top: 10px;
    }
}



