            // Format number with commas
            function formatNumber(num) {
                return num.toString().replace(/B(?=(d{3})+(?!d))/g, ",");
            }

            // Format currency
            function formatCurrency(num) {
                return '$' + num.toFixed(2).replace(/B(?=(d{3})+(?!d))/g, ",") + ' M';
            }

            // Get selected revenue sources from checkboxes
            function getSelectedRevenueSources() {
                const sources = [];
                $('input[name="revenue-source"]:checked').each(function() {
                    sources.push($(this).val());
                });
                return sources;
            }

            // Initialize dashboard on load
            $(document).ready(function() {
                // Ensure scrollbar is visible by forcing some content
                const checkboxContainer = document.querySelector('.checkbox-container');
                if (checkboxContainer) {
                    // Force scrollbar to be visible
                    checkboxContainer.style.overflowY = 'scroll';
                }

                // Load initial data
                loadSummaryStats(oilData.filter(item => item.revenue > 0));
                populateDataTable(oilData);
                initializeCharts(oilData.filter(item => item.revenue > 0));

                // Set up event listeners for immediate updates
                $('#year-filter').change(function() {
                    updateDashboard();
                });

                // Revenue source checkbox change handlers
                $('input[name="revenue-source"]').change(function() {
                    updateDashboard();
                });

                $('#view-type').change(function() {
                    updateDashboard();
                });

                // Make table rows interactive
                $(document).on('click', '#table-body tr', function() {
                    const year = parseInt($(this).find('td:first').text());

                    if ($(this).hasClass('selected-row')) {
                        // Deselect row
                        $(this).removeClass('selected-row');
                        selectedYears = selectedYears.filter(y => y !== year);
                    } else {
                        // Select row
                        $(this).addClass('selected-row');
                        selectedYears.push(year);
                    }

                    updateChartsWithSelectedYears();
                });

                // Toggle all rows selection
                $('#toggle-all').click(function() {
                    allYearsSelected = !allYearsSelected;

                    if (allYearsSelected) {
                        $('#table-body tr').addClass('selected-row');
                        selectedYears = oilData.map(item => item.year);
                        $(this).text('Deselect All Years');
                    } else {
                        $('#table-body tr').removeClass('selected-row');
                        selectedYears = [];
                        $(this).text('Select All Years');
                    }

                    updateChartsWithSelectedYears();
                });
