            function loadSummaryStats(data) {
                const totalProduction = data.reduce((sum, item) => sum + item.production, 0);
                const totalRevenue = data.reduce((sum, item) => sum + item.revenue, 0);
                const yearsWithRevenue = data.filter(item => item.revenue > 0).length;
                const avgAnnualRevenue = totalRevenue / (yearsWithRevenue || 1); // Avoid division by zero

                // Find peak revenue year
                let peakYear = '-';
                if (data.length > 0) {
                    const peakItem = data.reduce((peak, item) => 
                        item.revenue > (peak.revenue || 0) ? item : peak, {});
                    peakYear = peakItem.year || '-';
                }

                document.getElementById('total-production').textContent = formatNumber(totalProduction);
                document.getElementById('total-revenue').textContent = formatCurrency(totalRevenue);
                document.getElementById('avg-annual-revenue').textContent = formatCurrency(avgAnnualRevenue);
                document.getElementById('peak-year').textContent = peakYear;
            }

            function populateDataTable(data) {
                const tableBody = document.getElementById('table-body');
                tableBody.innerHTML = '';

                data.forEach(item => {
                    const row = document.createElement('tr');
                    if (selectedYears.includes(item.year)) {
                        row.classList.add('selected-row');
                    }

                    const yearCell = document.createElement('td');
                    yearCell.textContent = item.year;
                    row.appendChild(yearCell);

                    const productionCell = document.createElement('td');
                    productionCell.textContent = formatNumber(item.production);
                    row.appendChild(productionCell);

                    const revenueCell = document.createElement('td');
                    revenueCell.textContent = formatCurrency(item.revenue);
                    row.appendChild(revenueCell);

                    const royaltiesCell = document.createElement('td');
                    royaltiesCell.textContent = formatCurrency(item.royalties);
                    row.appendChild(royaltiesCell);

                    const capiCell = document.createElement('td');
                    capiCell.textContent = formatCurrency(item.capi);
                    row.appendChild(capiCell);

                    const citCell = document.createElement('td');
                    citCell.textContent = formatCurrency(item.cit);
                    row.appendChild(citCell);

                    const rentalsCell = document.createElement('td');
                    rentalsCell.textContent = formatCurrency(item.surfaceRentals);
                    row.appendChild(rentalsCell);

                    const otherCell = document.createElement('td');
                    otherCell.textContent = formatCurrency(item.other);
                    row.appendChild(otherCell);

                    tableBody.appendChild(row);
                });
            }

            function initializeCharts(data) {
                // Filter out years with zero revenue for better visualization
                const filteredData = data.filter(item => item.revenue > 0);

                // Revenue Trends Chart
                const revenueTrendsCtx = document.getElementById('revenue-trends-chart').getContext('2d');
                revenueChart = new Chart(revenueTrendsCtx, {
