                                }
                            },
                            x: {
                                title: {
                                    display: true,
                                    text: 'Year'
                                }
                            }
                        }
                    }
                });

                // Revenue Breakdown Chart
                const breakdownCtx = document.getElementById('revenue-breakdown-chart').getContext('2d');

                // Calculate totals for each revenue source
                const totalRoyalties = filteredData.reduce((sum, item) => sum + item.royalties, 0);
                const totalCapi = filteredData.reduce((sum, item) => sum + item.capi, 0);
                const totalCit = filteredData.reduce((sum, item) => sum + item.cit, 0);
                const totalRentals = filteredData.reduce((sum, item) => sum + item.surfaceRentals, 0);
                const totalOther = filteredData.reduce((sum, item) => sum + item.other, 0);

                breakdownChart = new Chart(breakdownCtx, {
                    type: 'pie',
                    data: {
                        labels: ['Royalties', 'CAPI', 'CIT', 'Surface Rentals', 'Other'],
                        datasets: [{
                            data: [totalRoyalties, totalCapi, totalCit, totalRentals, totalOther],
                            backgroundColor: [
                                '#ff9933',
                                '#333399',
                                '#ff7733',
                                '#6666cc',
                                '#ffcc99'
                            ],
                            borderWidth: 1
                        }]
