                                data: filteredData.map(item => item.revenue),
                                borderColor: '#ff9933',
                                backgroundColor: 'rgba(255, 153, 51, 0.1)',
                                yAxisID: 'y',
                                fill: true,
                                tension: 0.4
                            },
                            {
                                label: 'Production (Million Barrels)',
                                data: filteredData.map(item => item.production / 1000000),
                                borderColor: '#333399',
                                backgroundColor: 'rgba(51, 51, 153, 0.1)',
                                yAxisID: 'y1',
                                fill: true,
                                tension: 0.4
                            }
                        ]
                    },
                    options: {
                        responsive: true,
                        maintainAspectRatio: false,
                        scales: {
                            y: {
                                type: 'linear',
                                display: true,
                                position: 'left',
                                title: {
                                    display: true,
                                    text: 'Revenue (USD Million)'
