            function updateDashboard() {
                // Get filter values
                const yearRange = $('#year-filter').val();
                const revenueSources = getSelectedRevenueSources();
                const viewType = $('#view-type').val();

                // Filter data based on year range
                let filteredData = [...oilData];

                if (yearRange !== 'all') {
                    const [startYear, endYear] = yearRange.split('-').map(Number);
                    filteredData = filteredData.filter(item => item.year >= startYear && item.year <= endYear);
                }

                // Filter out zero revenue years
                filteredData = filteredData.filter(item => item.revenue > 0);

                // Update table and stats
                populateDataTable(filteredData);
                loadSummaryStats(filteredData);

                // Update charts based on selections
                updateCharts(filteredData, revenueSources, viewType);
            }

            function updateChartsWithSelectedYears() {
                // Get the current filters 
                const yearRange = $('#year-filter').val();
                const revenueSources = getSelectedRevenueSources();
                const viewType = $('#view-type').val();

                // Filter data based on year range first
                let filteredData = [...oilData];

                if (yearRange !== 'all') {
                    const [startYear, endYear] = yearRange.split('-').map(Number);
                    filteredData = filteredData.filter(item => item.year >= startYear && item.year <= endYear);
                }

                // Then filter by selected years (if any are selected)
                if (selectedYears.length > 0) {
                    filteredData = filteredData.filter(item => selectedYears.includes(item.year));
                }

                // Filter out zero revenue years
                filteredData = filteredData.filter(item => item.revenue > 0);

                // Update stats for selected data
                loadSummaryStats(filteredData);

                // Update charts
                updateCharts(filteredData, revenueSources, viewType);
            }

            function updateCharts(data, revenueSources, viewType) {
                if (data.length === 0) {
                    data = oilData.filter(item => item.revenue > 0);
                }

                // Prepare datasets for trend chart
                let datasets = [];

                // If no sources are selected, show total revenue
                if (!revenueSources || revenueSources.length === 0) {
                    datasets.push({
                        label: 'Total Revenue (USD Million)',
                        data: data.map(item => item.revenue),
                        backgroundColor: '#ff9933',
                        borderColor: '#ff9933',
                        borderWidth: 1
                    });
                } else {
                    // Add selected revenue sources
                    if (revenueSources.includes('Royalties')) {
                        datasets.push({
                            label: 'Royalties (USD Million)',
                            data: data.map(item => item.royalties),
                            backgroundColor: '#ff9933',
                            borderColor: '#ff9933',
                            borderWidth: 1
                        });
                    }

                    if (revenueSources.includes('CAPI')) {
                        datasets.push({
                            label: 'CAPI (USD Million)',
                            data: data.map(item => item.capi),
                            backgroundColor: '#333399',
                            borderColor: '#333399',
                            borderWidth: 1
                        });
                    }

                    if (revenueSources.includes('CIT')) {
                        datasets.push({
                            label: 'Corporate Income Tax (USD Million)',
                            data: data.map(item => item.cit),
                            backgroundColor: '#ff7733',
                            borderColor: '#ff7733',
                            borderWidth: 1
                        });
                    }

                    if (revenueSources.includes('SurfaceRentals')) {
                        datasets.push({
                            label: 'Surface Rentals (USD Million)',
                            data: data.map(item => item.surfaceRentals),
                            backgroundColor: '#6666cc',
                            borderColor: '#6666cc',
                            borderWidth: 1
                        });
                    }

                    if (revenueSources.includes('Other')) {
                        datasets.push({
                            label: 'Other Income (USD Million)',
                            data: data.map(item => item.other),
                            backgroundColor: '#ffcc99',
                            borderColor: '#ffcc99',
                            borderWidth: 1
                        });
                    }
                }

                // Update Revenue Trends Chart
                revenueChart.data.labels = data.map(item => item.year);
                revenueChart.data.datasets = datasets;

                // Change chart type if needed
                if (revenueChart.config.type !== viewType) {
                    revenueChart.config.type = viewType;
                }

                // If pie chart, adjust the datasets structure
                if (viewType === 'pie') {
                    // For pie chart, we need to adapt the data format
                    const sources = ['Royalties', 'CAPI', 'CIT', 'Surface Rentals', 'Other'];
                    const sourceData = [
                        data.reduce((sum, item) => sum + item.royalties, 0),
                        data.reduce((sum, item) => sum + item.capi, 0),
                        data.reduce((sum, item) => sum + item.cit, 0),
                        data.reduce((sum, item) => sum + item.surfaceRentals, 0),
                        data.reduce((sum, item) => sum + item.other, 0)
                    ];

                    revenueChart.data.datasets = [{
                        data: sourceData,
                        backgroundColor: ['#ff9933', '#333399', '#ff7733', '#6666cc', '#ffcc99'],
                        borderWidth: 1
                    }];
                    revenueChart.data.labels = sources;
                }

                revenueChart.update();

                // Update breakdown chart
                const totalRoyalties = data.reduce((sum, item) => sum + item.royalties, 0);
                const totalCapi = data.reduce((sum, item) => sum + item.capi, 0);
                const totalCit = data.reduce((sum, item) => sum + item.cit, 0);
                const totalRentals = data.reduce((sum, item) => sum + item.surfaceRentals, 0);
                const totalOther = data.reduce((sum, item) => sum + item.other, 0);

                breakdownChart.data.datasets[0].data = [
                    totalRoyalties, 
                    totalCapi, 
                    totalCit, 
                    totalRentals, 
                    totalOther
                ];
                breakdownChart.update();

                // Update the production vs revenue chart
                productionRevenueChart.data.labels = data.map(item => item.year);

                // Reset first dataset which shows revenue
                if (!revenueSources || revenueSources.length === 0) {
                    // Default to total revenue if no source selected
                    productionRevenueChart.data.datasets[0] = {
                        label: 'Revenue (USD Million)',
                        data: data.map(item => item.revenue),
                        borderColor: '#ff9933',
                        backgroundColor: 'rgba(255, 153, 51, 0.1)',
                        yAxisID: 'y',
                        fill: true,
                        tension: 0.4
                    };
                } else if (revenueSources.length === 1) {
                    // Single source selected
                    const source = revenueSources[0];
                    if (source === 'Royalties') {
                        productionRevenueChart.data.datasets[0] = {
                            label: 'Royalties (USD Million)',
                            data: data.map(item => item.royalties),
                            borderColor: '#ff9933',
                            backgroundColor: 'rgba(255, 153, 51, 0.1)',
                            yAxisID: 'y',
                            fill: true,
                            tension: 0.4
                        };
                    } else if (source === 'CAPI') {
                        productionRevenueChart.data.datasets[0] = {
                            label: 'CAPI (USD Million)',
                            data: data.map(item => item.capi),
                            borderColor: '#ff9933',
                            backgroundColor: 'rgba(255, 153, 51, 0.1)',
                            yAxisID: 'y',
                            fill: true,
                            tension: 0.4
                        };
                    } else if (source === 'CIT') {
                        productionRevenueChart.data.datasets[0] = {
                            label: 'CIT (USD Million)',
                            data: data.map(item => item.cit),
                            borderColor: '#ff9933',
                            backgroundColor: 'rgba(255, 153, 51, 0.1)',
                            yAxisID: 'y',
                            fill: true,
                            tension: 0.4
                        };
                    } else if (source === 'SurfaceRentals') {
                        productionRevenueChart.data.datasets[0] = {
                            label: 'Surface Rentals (USD Million)',
                            data: data.map(item => item.surfaceRentals),
                            borderColor: '#ff9933',
                            backgroundColor: 'rgba(255, 153, 51, 0.1)',
                            yAxisID: 'y',
                            fill: true,
                            tension: 0.4
                        };
                    } else if (source === 'Other') {
                        productionRevenueChart.data.datasets[0] = {
                            label: 'Other Income (USD Million)',
                            data: data.map(item => item.other),
                            borderColor: '#ff9933',
                            backgroundColor: 'rgba(255, 153, 51, 0.1)',
                            yAxisID: 'y',
                            fill: true,
                            tension: 0.4
                        };
                    }
                } else {
                    // Multiple sources - show sum of selected
                    const selectedData = data.map(item => {
                        let sum = 0;
                        if (revenueSources.includes('Royalties')) sum += item.royalties;
                        if (revenueSources.includes('CAPI')) sum += item.capi;
                        if (revenueSources.includes('CIT')) sum += item.cit;
                        if (revenueSources.includes('SurfaceRentals')) sum += item.surfaceRentals;
                        if (revenueSources.includes('Other')) sum += item.other;
                        return sum;
                    });

                    productionRevenueChart.data.datasets[0] = {
                        label: 'Selected Sources (USD Million)',
                        data: selectedData,
                        borderColor: '#ff9933',
                        backgroundColor: 'rgba(255, 153, 51, 0.1)',
                        yAxisID: 'y',
                        fill: true,
                        tension: 0.4
                    };
                }

                // Production data
                productionRevenueChart.data.datasets[1] = {
                    label: 'Production (Million Barrels)',
                    data: data.map(item => item.production / 1000000),
                    borderColor: '#333399',
                    backgroundColor: 'rgba(51, 51, 153, 0.1)',
                    yAxisID: 'y1',
                    fill: true,
                    tension: 0.4
                };

                productionRevenueChart.update();
            }
        })();


