        document.addEventListener('DOMContentLoaded', function() {
            const contactForm = document.getElementById('contactForm');
            const formSuccess = document.getElementById('formSuccess');
            const formError = document.getElementById('formError');

            contactForm.addEventListener('submit', function(e) {
                e.preventDefault();

                // Reset any previous error states
                const errorGroups = document.querySelectorAll('.input-group.error');
                errorGroups.forEach(group => group.classList.remove('error'));

                formSuccess.style.display = 'none';
                formError.style.display = 'none';

                // Validate form
                let isValid = true;

                // Name validation
                const nameInput = document.getElementById('fullName');
                if (!nameInput.value.trim()) {
                    document.querySelector('[for="fullName"]').parentElement.classList.add('error');
                    isValid = false;
                }

                // Email validation
                const emailInput = document.getElementById('email');
                const emailPattern = /^[^s@]+@[^s@]+.[^s@]+$/;
                if (!emailPattern.test(emailInput.value.trim())) {
                    document.querySelector('[for="email"]').parentElement.classList.add('error');
                    isValid = false;
                }

                // Subject validation
                const subjectInput = document.getElementById('subject');
                if (subjectInput.value === '') {
                    document.querySelector('[for="subject"]').parentElement.classList.add('error');
                    isValid = false;
                }

                // Message validation
                const messageInput = document.getElementById('message');
                if (!messageInput.value.trim()) {
                    document.querySelector('[for="message"]').parentElement.classList.add('error');
                    isValid = false;
                }

                if (isValid) {
                    // For demonstration purposes, we'll just show the success message
                    // In a real implementation, you would send the form data to a server

                    // Simulate form submission with delay
                    const submitBtn = contactForm.querySelector('.submit-btn');
                    submitBtn.disabled = true;
                    submitBtn.innerHTML = 'Sending...';

                    setTimeout(() => {
                        formSuccess.style.display = 'block';
                        contactForm.reset();
                        submitBtn.disabled = false;
                        submitBtn.innerHTML = '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="22" y1="2" x2="11" y2="13"></line><polygon points="22 2 15 22 11 13 2 9 22 2"></polygon></svg>Send Message';

                        // Auto-hide success message after 5 seconds
                        setTimeout(() => {
                            formSuccess.style.display = 'none';
                        }, 5000);
                    }, 1500);
                }
            });
        });


