                }
            ];

            // Charts objects
            let revenueChart, allocationChart;

            // Calculate total revenue
            const calculateTotalRevenue = (years) => {
                let total = 0;
                years.forEach(year => {
                    total += revenueDataByYear[year].amount;
                });
                return total;
            };

            // Calculate percent change
            const calculatePercentChange = (current, previous) => {
                if (previous === 0) return 100;
                return Math.round(((current - previous) / previous) * 100);
            };

            // Find category with highest allocation
            const findTopAllocation = (allocationData) => {
                let topCategory = '';
                let topValue = 0;

                Object.entries(allocationData).forEach(([category, value]) => {
                    if (value > topValue) {
                        topValue = value;
                        topCategory = category;
                    }
                });

                return [topCategory, topValue];
            };

            // Calculate average annual revenue
            const calculateAverageRevenue = (years) => {
                let total = 0;
                years.forEach(year => {
                    total += revenueDataByYear[year].amount;
                });
                return Math.round(total / years.length);
            };

            // Calculate peak revenue
            const calculatePeakRevenue = (years) => {
                let peak = 0;
                let peakYear = '';

                years.forEach(year => {
                    if (revenueDataByYear[year].amount > peak) {
                        peak = revenueDataByYear[year].amount;
                        peakYear = year;
                    }
                });

                return [peak, peakYear];
            };

            // Update dashboard with filtered data
            const updateDashboard = (timeframe, category) => {
                // Determine years to include based on timeframe
                let yearsToInclude = [];
                let previousYears = [];

                if (timeframe === 'all') {
                    yearsToInclude = Object.keys(revenueDataByYear);
                    previousYears = [];  // No previous period for all time
                } else if (timeframe === '5year') {
                    yearsToInclude = ['2020', '2021', '2022', '2023', '2024'];
                    previousYears = ['2015', '2016', '2017', '2018', '2019'];
                } else {
                    // If specific year selected
                    yearsToInclude = [timeframe];
                    // Previous year as comparison
                    const prevYear = parseInt(timeframe) - 1;
                    if (prevYear >= 2010) {  // Make sure we don't go before our data range
                        previousYears = [prevYear.toString()];
                    }
                }

                // Calculate KPIs
                const totalRevenue = calculateTotalRevenue(yearsToInclude);
                const averageRevenue = calculateAverageRevenue(yearsToInclude);
                const [peakRevenue, peakYear] = calculatePeakRevenue(yearsToInclude);

                // Calculate previous period metrics for comparison
                const previousTotalRevenue = previousYears.length > 0 ? calculateTotalRevenue(previousYears) : 0;
                const previousAvgRevenue = previousYears.length > 0 ? calculateAverageRevenue(previousYears) : 0;

                // Calculate percent changes
                const revenuePercentChange = calculatePercentChange(totalRevenue, previousTotalRevenue);
                const avgRevenuePercentChange = calculatePercentChange(averageRevenue, previousAvgRevenue);

                // Get active projects count
                const matchingProjects = projectsFullData.filter(project => {
                    const yearMatch = yearsToInclude.includes(project.year.toString());
                    const categoryMatch = category === 'all' || project.category.toLowerCase() === category;
                    return yearMatch && categoryMatch;
                });

                const activeProjectsCount = matchingProjects.length;

                // Previous period active projects
                const previousProjects = previousYears.length > 0 ? 
                    projectsFullData.filter(project => {
                        const yearMatch = previousYears.includes(project.year.toString());
                        const categoryMatch = category === 'all' || project.category.toLowerCase() === category;
                        return yearMatch && categoryMatch;
                    }).length : 0;

                const projectsPercentChange = calculatePercentChange(activeProjectsCount, previousProjects);

                // Average allocation percentages
                let combinedAllocation = {
                    'Infrastructure': 0,
                    'Education': 0,
                    'Health': 0,
                    'Agriculture': 0,
                    'Others': 0
                };

                yearsToInclude.forEach(year => {
                    Object.entries(revenueDataByYear[year].allocation).forEach(([category, percentage]) => {
                        combinedAllocation[category] += percentage;
                    });
                });

                Object.keys(combinedAllocation).forEach(category => {
                    combinedAllocation[category] = Math.round(combinedAllocation[category] / yearsToInclude.length);
                });

                // Update KPI cards with values and trends
                $('#total-revenue-value').text('$' + totalRevenue.toLocaleString() + 'M');

