                        <span class="trend-value ${avgRevenuePercentChange >= 0 ? 'positive' : 'negative'}">
                            ${avgRevenuePercentChange >= 0 ? '↑' : '↓'} ${Math.abs(avgRevenuePercentChange)}%
                        </span>
