                            ${projectsPercentChange >= 0 ? '↑' : '↓'} ${Math.abs(projectsPercentChange)}%
                        </span>
                    `);
                } else {
                    $('#active-projects-trend').html('');
                }

                // Update revenue chart
                updateRevenueChart(yearsToInclude);

                // Update allocation chart
                updateAllocationChart(combinedAllocation);

                // Update projects
                updateProjects(yearsToInclude, category);
            };

            // Update revenue chart
            const updateRevenueChart = (years) => {
                // Prepare chart data
                const labels = years.sort();
                const data = labels.map(year => revenueDataByYear[year].amount);

                // If chart exists, update it
                if (revenueChart) {
                    revenueChart.data.labels = labels;
                    revenueChart.data.datasets[0].data = data;
                    revenueChart.update();
                } else {
                    // Create new chart
