        }

        #oilmoney-dashboard .kpi-card-average {
            border-top: 4px solid #2ecc71;
        }

        #oilmoney-dashboard .kpi-card-peak {
            border-top: 4px solid #f39c12;
        }

        #oilmoney-dashboard .kpi-card-projects {
