    transform: translateY(30px);
    animation: fade-in 0.6s ease forwards;
}

@keyframes fade-in {
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Tooltips */
.tooltip {
    position: relative;
    cursor: pointer;
}

.tooltip::after {
    content: attr(data-tooltip);
    position: absolute;
    bottom: 125%;
    left: 50%;
    transform: translateX(-50%);
    background-color: rgba(0, 0, 0, 0.8);
    color: white;
    padding: 8px 12px;
    border-radius: 4px;
    font-size: 14px;
    white-space: nowrap;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s, visibility 0.3s;
    z-index: 10;
    pointer-events: none;
    font-weight: normal;
}

.tooltip::before {
    content: "";
    position: absolute;
    bottom: 125%;
    left: 50%;
    transform: translateX(-50%) translateY(100%);
    border-width: 6px;
    border-style: solid;
    border-color: rgba(0, 0, 0, 0.8) transparent transparent transparent;
    opacity: 0;
    visibility: hidden;
    transition: opacity 0.3s, visibility 0.3s;
    z-index: 10;
    pointer-events: none;
}

.tooltip:hover::after, .tooltip:hover::before {
    opacity: 1;
    visibility: visible;
}

/* Avoid tooltip overflow on edges */
.tooltip:hover::after {
    white-space: normal;
    width: max-content;
    max-width: 300px;
    word-wrap: break-word;
}

/* Responsive Design */
@media (max-width: 768px) {
    .petroleum-dashboard {
        padding: 20px 15px;
    }

    .institutions-grid {
        grid-template-columns: 1fr;
    }

    .framework-flow-container {
        flex-direction: column;
    }

    .flow-stage {
        width: 90%;
        margin: 10px auto;
    }

    .flow-arrow {
        width: 2px;
        height: 30px;
        margin: 10px auto;
    }

    .flow-arrow::after {
        right: -4px;
        top: auto;
        bottom: 0;
        border-left: 5px solid transparent;
        border-right: 5px solid transparent;
        border-top: 8px solid var(--medium-gray);
        border-bottom: none;
    }

    .reporting-grid {
        grid-template-columns: 1fr;
    }

    .tooltip::after {
        width: 200px;
        left: 0;
        transform: none;
    }

    .tooltip::before {
        left: 10px;
        transform: translateY(100%);
    }
}


