.flow-node.extra-small {
    max-width: 200px;
    padding: 10px;
}

.node-content {
    text-align: center;
}

.node-title {
    margin-bottom: 5px;
}

.node-title strong {
    font-size: 18px;
    font-weight: 600;
    color: var(--dark-gray);
}

.flow-node.small .node-title strong,
.flow-node.extra-small .node-title strong {
    font-size: 16px;
}

.node-subtitle {
    font-size: 16px;
    color: var(--medium-gray);
}

.flow-node.small .node-subtitle,
.flow-node.extra-small .node-subtitle {
    font-size: 14px;
}

.node-action {
    margin-top: 10px;
    font-size: 14px;
    color: var(--secondary);
    text-align: center;
    font-weight: 500;
    background-color: var(--secondary-light);
    padding: 6px 12px;
    border-radius: 20px;
    display: inline-block;
    position: relative;
    left: 50%;
    transform: translateX(-50%);
    opacity: 1;
    transition: background-color 0.3s ease, color 0.3s ease;
}

.flow-node:hover .node-action {
    background-color: var(--secondary);
    color: var(--white);
}

/* Connector Lines */
.connector-line {
    height: 40px;
    width: 2px;
    background-color: var(--medium-gray);
    position: absolute;
    top: 100%;
    left: 50%;
    transform: translateX(-50%);
}

.connector-branch {
    width: 70%;
    height: 2px;
    background-color: var(--medium-gray);
    position: absolute;
    top: 100%;
    left: 50%;
    transform: translateX(-50%);
}

.connector-branch.small {
    width: 100%;
}

/* Branch Styles */
.branch-container {
    display: flex;
    justify-content: space-around;
    margin: 50px 0;
}

.flow-branch {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 33%;
}

.branch-line {
    height: 50px;
    width: 2px;
    background-color: var(--medium-gray);
    margin-bottom: 20px;
}

.branch-line.small {
    height: 30px;
}

.sub-branch-container {
    display: flex;
    justify-content: space-around;
    width: 100%;
    margin-top: 20px;
}

.flow-branch.sub-branch-1,
.flow-branch.sub-branch-2 {
    width: 45%;
}

/* Oversight Banner */
.oversight-container {
    margin-top: 40px;
}

.oversight-banner {
    background-color: var(--secondary-light);
    padding: 20px;
    border-radius: 10px;
    width: 100%;
    text-align: center;
    cursor: pointer;
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.oversight-banner:hover {
    transform: translateY(-5px);
    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.12);
}

.oversight-title {
    margin-bottom: 5px;
}

.oversight-title strong {
    font-size: 20px;
    font-weight: 600;
    color: var(--secondary);
}

.oversight-bodies {
    font-size: 16px;
    color: var(--medium-gray);
}

/* Dashboard Controls */
.dashboard-controls {
    display: flex;
    justify-content: center;
    flex-wrap: wrap;
    gap: 10px;
    margin: 30px 0;
}

.control-button {
    padding: 10px 20px;
    background-color: var(--light-gray);
    border-radius: 30px;
    cursor: pointer;
    transition: background-color 0.3s ease, color 0.3s ease;
    font-size: 16px;
}

.control-button:hover {
    background-color: var(--secondary-light);
}

.control-button.active {
    background-color: var(--secondary);
    color: var(--white);
}

/* Dashboard Info Panel */
.dashboard-info-panel {
    margin-top: 30px;
    padding: 20px;
    background-color: var(--white);
    border-radius: 10px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.08);
}

.info-title {
    margin-bottom: 15px;
}

.info-title strong {
    font-size: 20px;
    font-weight: 600;
    color: var(--dark-gray);
}

.info-content p {
    font-size: 16px;
    line-height: 1.6;
    color: var(--medium-gray);
    margin-bottom: 15px;
}

.key-insights {
    list-style-type: none;
    padding: 0;
    display: flex;
    flex-wrap: wrap;
    gap: 15px;
}

.key-insights li {
    flex-basis: calc(50% - 15px);
    background-color: var(--light-gray);
    padding: 15px;
    border-radius: 8px;
    font-size: 16px;
}

.insight-highlight {
    color: var(--secondary);
    font-weight: 600;
    display: block;
    margin-bottom: 5px;
}

/* Modal Styles */
.modal-container {
    position: relative;
}

.modal-overlay {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background-color: rgba(0, 0, 0, 0.5);
    z-index: 998;
}

.modal-popup {
    display: none;
    position: fixed;
    top: 60%;
    left: 50%;
    transform: translate(-50%, -50%);
    background-color: var(--white);
    border-radius: 10px;
    z-index: 999;
    width: 80%;
    max-width: 700px;
    height: 60vh;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
    display: flex;
    flex-direction: column;
}

.modal-content {
    display: flex;
    flex-direction: column;
    height: 100%;
}

.modal-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 15px 20px;
    border-bottom: 1px solid var(--light-gray);
    background-color: var(--white);
    z-index: 2;
    border-radius: 10px 10px 0 0;
    flex-shrink: 0;
}

.modal-title strong {
    font-size: 22px;
    font-weight: 600;
    color: var(--secondary);
}

.modal-close {
    font-size: 28px;
    cursor: pointer;
    color: var(--medium-gray);
    transition: color 0.3s ease;
}

.modal-close:hover {
    color: var(--danger);
}

.modal-body {
    padding: 20px;
    overflow-y: scroll;
    flex-grow: 1;
    scrollbar-width: thin;
    scrollbar-color: var(--medium-gray) var(--light-gray);
}

/* Always show scrollbar */
.modal-body::-webkit-scrollbar {
    width: 12px;
    background-color: var(--light-gray);
    border-radius: 6px;
}

.modal-body::-webkit-scrollbar-thumb {
    background-color: var(--medium-gray);
    border-radius: 6px;
    border: 3px solid var(--light-gray);
}

.modal-body::-webkit-scrollbar-thumb:hover {
    background-color: var(--dark-gray);
}

.modal-section {
    margin-bottom: 20px;
}

.section-title {
    font-size: 18px;
    font-weight: 600;
    color: var(--dark-gray);
    display: block;
    margin-bottom: 10px;
}

.modal-list {
    list-style-type: none;
    padding-left: 0;
    margin-bottom: 15px;
}

.modal-list li {
    margin-bottom: 8px;
    font-size: 16px;
    line-height: 1.5;
    position: relative;
    padding-left: 18px;
}

.modal-list li::before {
    content: "•";
    color: var(--secondary);
    position: absolute;
    left: 0;
}

.modal-list li ul {
    list-style-type: none;
    padding-left: 18px;
    margin-top: 8px;
}

.modal-list li ul li::before {
    content: "◦";
}

.feature-list li {
    background-color: var(--light-gray);
    padding: 12px 12px 12px 30px;
    margin-bottom: 10px;
    border-radius: 8px;
}

.feature-list li::before {
    left: 10px;
}

.modal-metrics {
    display: flex;
    justify-content: space-around;
    margin-top: 25px;
    padding-top: 20px;
    border-top: 1px solid var(--light-gray);
    flex-wrap: wrap;
}

.metric-item {
    text-align: center;
    flex: 1;
    min-width: 120px;
    margin-bottom: 15px;
}

.metric-value {
    font-size: 24px;
    font-weight: 700;
    color: var(--secondary);
    margin-bottom: 5px;
}

.metric-label {
    font-size: 16px;
    color: var(--medium-gray);
}

/* Chart Styles for Modals */
.modal-chart {
    margin: 20px 0;
    display: flex;
    flex-direction: column;
    align-items: center;
}

.pie-allocation {
    position: relative;
    width: 200px;
    height: 200px;
    border-radius: 50%;
    overflow: hidden;
    margin: 0 auto 20px;
}

.pie-slice {
    position: absolute;
    width: 100%;
    height: 100%;
    transform-origin: center;
}

.slice-70 {
    background-color: var(--secondary);
    clip-path: polygon(50% 50%, 50% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 0%, 50% 0%);
    transform: rotate(0deg);
}

.slice-15 {
    background-color: var(--primary);
    clip-path: polygon(50% 50%, 100% 0%, 100% 50%);
    transform: rotate(252deg);
}

.slice-15-split {
    background-color: var(--tertiary);
    clip-path: polygon(50% 50%, 100% 0%, 100% 54%);
    transform: rotate(306deg);
}

.pie-center {
    position: absolute;
    width: 100px;
    height: 100px;
    background-color: white;
    border-radius: 50%;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    color: var(--dark-gray);
    font-size: 18px;
    box-shadow: 0 1px 5px rgba(0, 0, 0, 0.1);
}

.allocation-legend {
    width: 100%;
}

.legend-item {
    display: flex;
    align-items: center;
    margin-bottom: 8px;
}

.legend-color {
    width: 16px;
    height: 16px;
    border-radius: 3px;
    margin-right: 8px;
}

.abfa-color {
    background-color: var(--secondary);
}

.gnpc-color {
    background-color: var(--primary);
}

.gpf-color {
    background-color: var(--tertiary);
}

.legend-text {
    font-size: 16px;
    color: var(--dark-gray);
}

/* Horizontal Bars for ABFA Modal */
.horizontal-bars {
    margin: 20px 0;
}

.horizontal-bar {
    display: flex;
    align-items: center;
    margin-bottom: 12px;
}

.bar-label {
    width: 120px;
    font-size: 16px;
}

.bar-track {
    flex-grow: 1;
    height: 20px;
    background-color: var(--light-gray);
    border-radius: 10px;
    overflow: hidden;
    margin: 0 15px;
}

.bar-fill {
    height: 100%;
    background-color: var(--secondary);
    border-radius: 10px;
    transition: width 1s ease;
}

.bar-value {
    width: 50px;
    text-align: right;
    font-size: 16px;
    font-weight: 600;
}

/* Utilization Grid */
.utilization-grid, .oversight-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
    gap: 20px;
    margin-bottom: 20px;
}

.utilization-card, .oversight-card {
    background-color: var(--light-gray);
    border-radius: 8px;
    padding: 15px;
}

.utilization-header, .oversight-header {
    margin-bottom: 10px;
    padding-bottom: 10px;
    border-bottom: 1px solid rgba(0, 0, 0, 0.1);
}

.utilization-header strong, .oversight-header strong {
    font-size: 18px;
    font-weight: 600;
    color: var(--dark-gray);
}

.label {
    display: block;
    margin: 12px 0 5px;
    font-size: 16px;
    color: var(--secondary);
}

/* Split Items for GPF Modal */
.modal-split {
    display: flex;
    flex-wrap: wrap;
    gap: 20px;
    margin-bottom: 20px;
}

.split-item {
    flex: 1;
    min-width: 280px;
    background-color: var(--light-gray);
    border-radius: 8px;
    padding: 15px;
}

.split-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 10px;
    padding-bottom: 10px;
    border-bottom: 1px solid rgba(0, 0, 0, 0.1);
}

.split-header strong {
    font-size: 18px;
    font-weight: 600;
    color: var(--dark-gray);
}

.split-value {
    font-size: 16px;
    font-weight: 600;
    color: var(--secondary);
    background-color: var(--secondary-light);
    padding: 5px 10px;
    border-radius: 20px;
}

/* Tab Content Control */
.section-content {
    display: block; /* Initially show all content */
}

/* Animations */
.animate-in {
    opacity: 0;
    transform: translateY(30px);
    animation: fade-in 0.6s ease forwards;
}

@keyframes fade-in {
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* Responsive Styles */
@media (max-width: 768px) {
    .petroleum-dashboard {
        padding: 20px 15px;
    }

    .flow-node {
        width: 90%;
    }

    .branch-container {
        flex-direction: column;
        align-items: center;
    }

    .flow-branch {
        width: 90%;
        margin-bottom: 30px;
    }

    .key-insights li {
        flex-basis: 100%;
    }

    .modal-popup {
        width: 95%;
        height: 70vh;
    }

    .modal-split {
        flex-direction: column;
    }

    .split-item {
        min-width: auto;
    }

    .modal-metrics {
        flex-wrap: wrap;
    }

    .metric-item {
        flex-basis: 50%;
        margin-bottom: 15px;
    }

    .horizontal-bar {
        flex-wrap: wrap;
    }

    .bar-label {
        width: 100%;
        margin-bottom: 5px;
    }

    .bar-track {
        margin: 5px 0;
    }

    .node-action {
        display: block;
        width: 80%;
        margin: 10px auto 0;
    }
}

@media (max-width: 500px) {
    .metric-item {
        flex-basis: 100%;
    }
}



document.addEventListener('DOMContentLoaded', function() {
    // Modal functionality
    const modalTriggers = document.querySelectorAll('.tooltip-trigger');
    const modalOverlay = document.querySelector('.modal-overlay');
    const modalCloseButtons = document.querySelectorAll('.modal-close');
    const modals = document.querySelectorAll('.modal-popup');

    // Open modal when clicking on a trigger element
    modalTriggers.forEach(trigger => {
        trigger.addEventListener('click', function() {
            const modalId = this.getAttribute('data-modal');
            const modal = document.getElementById(modalId);

            if (modal) {
                modalOverlay.style.display = 'block';
                modal.style.display = 'block';

                // Add animation class to the modal
                setTimeout(() => {
                    modal.classList.add('active');
                }, 10);
            }
        });
    });

    // Close modal when clicking the close button
    modalCloseButtons.forEach(closeBtn => {
        closeBtn.addEventListener('click', closeModals);
    });

    // Close modal when clicking outside the modal
    modalOverlay.addEventListener('click', closeModals);

    function closeModals() {
        modals.forEach(modal => {
            modal.style.display = 'none';
            modal.classList.remove('active');
        });
        modalOverlay.style.display = 'none';
    }

    // Dashboard view controls
    const controlButtons = document.querySelectorAll('.control-button');
    const allSections = document.querySelectorAll('.section-content');

    controlButtons.forEach(button => {
        button.addEventListener('click', function() {
            // Remove active class from all buttons
            controlButtons.forEach(btn => btn.classList.remove('active'));

            // Add active class to clicked button
            this.classList.add('active');

            // Get the view type
            const viewType = this.getAttribute('data-view');

            // Handle view changes
            handleViewChange(viewType);
        });
    });

    function handleViewChange(viewType) {
        if (viewType === 'all') {
            // Show all sections
            allSections.forEach(section => {
                section.style.display = 'block';
            });
        } else {
            // Hide all sections first
            allSections.forEach(section => {
                section.style.display = 'none';
            });

            // Show only relevant sections based on view type
            if (viewType === 'collection') {
                document.getElementById('collection-section').style.display = 'block';
                document.getElementById('fund-section').style.display = 'block';
            } else if (viewType === 'allocation') {
                document.getElementById('fund-section').style.display = 'block';
                document.getElementById('allocation-section').style.display = 'block';
                document.getElementById('distribution-section').style.display = 'block';
            } else if (viewType === 'utilization') {
                document.getElementById('distribution-section').style.display = 'block';
                document.getElementById('utilization-section').style.display = 'block';
            } else if (viewType === 'oversight') {
                document.getElementById('oversight-section').style.display = 'block';
            }
        }
    }

    // Initialize with all sections visible
    handleViewChange('all');
});
