        // Initialize map
        function initGhanaMap() {
            const mapContainer = document.getElementById('ghana-map');

            ghanaRegions.forEach(region => {
                const regionElement = document.createElement('div');
                regionElement.className = 'ghana-region';
                regionElement.style.left = `${region.x}%`;
                regionElement.style.top = `${region.y}%`;
                regionElement.style.width = `${region.width}%`;
                regionElement.style.height = `${region.height}%`;

                regionElement.addEventListener('click', (e) => {
                    const regionProjects = ghanaProjects.filter(project => 
                        region.projects.includes(project.id)
                    );

                    showGhanaRegionInfo(region, regionProjects, e);
                });

                mapContainer.appendChild(regionElement);
            });
        }

        function showGhanaRegionInfo(region, regionProjects, event) {
            // Remove any existing info boxes
            const existingInfo = document.querySelector('.ghana-region-info');
            if (existingInfo) {
                existingInfo.remove();
            }

            // Create new info box
            const infoElement = document.createElement('div');
            infoElement.className = 'ghana-region-info';

            let infoContent = `<h3>${region.name} Region</h3>`;

            if (regionProjects.length > 0) {
                infoContent += '<p>Oil-funded projects in this region:</p><ul>';
                regionProjects.forEach(project => {
                    infoContent += `<li>${project.name} (${project.sector})</li>`;
                });
                infoContent += '</ul>';
            } else {
                infoContent += '<p>No major oil-funded projects recorded in this region.</p>';
            }

            infoElement.innerHTML = infoContent;

            // Position the info box
            const mapContainer = document.getElementById('ghana-map');
            const rect = mapContainer.getBoundingClientRect();
            const x = event.clientX - rect.left;
            const y = event.clientY - rect.top;

            infoElement.style.left = `${x + 20}px`;
            infoElement.style.top = `${y - 20}px`;

            // Adjust if box goes outside the container
            setTimeout(() => {
                const infoRect = infoElement.getBoundingClientRect();
                if (infoRect.right > rect.right) {
                    infoElement.style.left = `${x - infoRect.width - 20}px`;
                }
                if (infoRect.bottom > rect.bottom) {
                    infoElement.style.top = `${y - infoRect.height - 20}px`;
                }
            }, 0);

            mapContainer.appendChild(infoElement);
            infoElement.style.display = 'block';

            // Close when clicking elsewhere
            document.addEventListener('click', function closeInfo(e) {
                if (!infoElement.contains(e.target) && !event.target.contains(e.target)) {
                    infoElement.remove();
                    document.removeEventListener('click', closeInfo);
                }
            });
        }

        // Initialize table
        function initGhanaTable() {
            const tableBody = document.querySelector('#ghana-projects-table tbody');

            // Clear table
            tableBody.innerHTML = '';

            // Add projects to table
            ghanaProjects.forEach(project => {
                const row = document.createElement('tr');

                row.innerHTML = `
                    <td>${project.name}</td>
                    <td>${project.sector}</td>
                    <td>${project.region}</td>
                    <td>${project.year}</td>
                    <td><span class="ghana-status ghana-${project.status.toLowerCase()}">${project.status}</span></td>
                `;

                tableBody.appendChild(row);
            });

            // Add sorting functionality
            const headers = document.querySelectorAll('#ghana-projects-table th');
            headers.forEach(header => {
                header.addEventListener('click', () => {
                    const sortBy = header.getAttribute('data-sort');
                    sortGhanaTable(sortBy);
                });
            });
        }

        // Sort table function
        let ghanaSortDirection = {};
        function sortGhanaTable(column) {
            // Toggle sort direction
            ghanaSortDirection[column] = ghanaSortDirection[column] === 'asc' ? 'desc' : 'asc';

            // Sort projects
            const sortedProjects = [...ghanaProjects].sort((a, b) => {
                if (column === 'year') {
                    return ghanaSortDirection[column] === 'asc' 
                        ? a[column] - b[column] 
                        : b[column] - a[column];
                } else {
                    return ghanaSortDirection[column] === 'asc'
                        ? a[column].localeCompare(b[column])
                        : b[column].localeCompare(a[column]);
                }
            });

            // Clear and rebuild table
            const tableBody = document.querySelector('#ghana-projects-table tbody');
            tableBody.innerHTML = '';

            sortedProjects.forEach(project => {
                const row = document.createElement('tr');
                row.innerHTML = `
                    <td>${project.name}</td>
                    <td>${project.sector}</td>
                    <td>${project.region}</td>
                    <td>${project.year}</td>
                    <td><span class="ghana-status ghana-${project.status.toLowerCase()}">${project.status}</span></td>
                `;
                tableBody.appendChild(row);
            });

            // Update headers to show sort direction
            const headers = document.querySelectorAll('#ghana-projects-table th');
            headers.forEach(header => {
                const headerColumn = header.getAttribute('data-sort');
                header.textContent = header.textContent.replace(' ▲', '').replace(' ▼', '');

                if (headerColumn === column) {
                    header.textContent += ghanaSortDirection[column] === 'asc' ? ' ▲' : ' ▼';
                }
            });
        }

        // Create spotlight image
        function createGhanaSpotlightImage() {
            const canvas = document.createElement('canvas');
            canvas.width = 500;
            canvas.height = 300;
            const ctx = canvas.getContext('2d');

            // Background
            ctx.fillStyle = '#E6F3F7';
            ctx.fillRect(0, 0, 500, 300);

            // Water
            ctx.fillStyle = '#124559';
            ctx.fillRect(0, 200, 500, 100);

            // Port structure
            ctx.fillStyle = '#666666';
            ctx.fillRect(80, 180, 340, 20);

            // Containers
            const colors = ['#E63946', '#457B9D', '#1D3557', '#F1FAEE', '#A8DADC'];
            for (let i = 0; i < 16; i++) {
                ctx.fillStyle = colors[i % colors.length];
                ctx.fillRect(100 + (i % 8) * 35, 150 - Math.floor(i / 8) * 25, 30, 20);
            }

            // Cranes
            ctx.fillStyle = '#F4A261';
            ctx.fillRect(130, 80, 8, 100);
            ctx.fillRect(130, 70, 80, 10);

            ctx.fillStyle = '#E76F51';
            ctx.fillRect(300, 60, 8, 120);
            ctx.fillRect(260, 60, 80, 10);

            // Ships
            ctx.fillStyle = '#2A9D8F';
            ctx.beginPath();
            ctx.moveTo(400, 230);
            ctx.lineTo(450, 230);
            ctx.lineTo(440, 260);
            ctx.lineTo(410, 260);
            ctx.closePath();
            ctx.fill();

            ctx.fillStyle = '#264653';
            ctx.beginPath();
            ctx.moveTo(40, 250);
            ctx.lineTo(90, 250);
            ctx.lineTo(85, 280);
            ctx.lineTo(45, 280);
            ctx.closePath();
            ctx.fill();

            // Convert to image
            const spotlightImage = document.getElementById('ghana-spotlight-image');
            spotlightImage.style.backgroundImage = `url(${canvas.toDataURL()})`;
            spotlightImage.style.backgroundSize = 'cover';
            spotlightImage.style.backgroundPosition = 'center';
        }

        // Initialize charts
        function initGhanaCharts() {
            // Calculate data for charts
            const sectorData = {};
            const statusData = { 'Completed': 0, 'Ongoing': 0, 'Planned': 0 };

            ghanaProjects.forEach(project => {
                // Count by sector
                if (sectorData[project.sector]) {
                    sectorData[project.sector]++;
                } else {
                    sectorData[project.sector] = 1;
                }

                // Count by status
                statusData[project.status]++;
            });

            // Bar chart for sectors
            const barCtx = document.getElementById('ghana-bar-chart').getContext('2d');
            new Chart(barCtx, {
                type: 'bar',
                data: {
                    labels: Object.keys(sectorData),
                    datasets: [{
                        label: 'Number of Projects',
                        data: Object.values(sectorData),
                        backgroundColor: [
                            '#124559', '#01949A', '#E9D985', '#E56997', '#A8DADC',
                            '#457B9D', '#1D3557', '#F4A261', '#E76F51', '#2A9D8F'
                        ],
                        borderWidth: 1
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    scales: {
                        y: {
                            beginAtZero: true,
                            ticks: {
                                precision: 0
                            }
                        }
                    }
                }
            });

            // Pie chart for status
            const pieCtx = document.getElementById('ghana-pie-chart').getContext('2d');
            new Chart(pieCtx, {
                type: 'pie',
                data: {
                    labels: Object.keys(statusData),
                    datasets: [{
                        label: 'Project Status',
                        data: Object.values(statusData),
                        backgroundColor: [
                            '#28a745', '#ffc107', '#17a2b8'
                        ],
                        borderWidth: 1
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false
                }
            });
        }

        // Initialize all components
        document.addEventListener('DOMContentLoaded', function() {
            initGhanaMap();
            initGhanaTable();
            createGhanaSpotlightImage();
            initGhanaCharts();
        });


