        }

        .report-card-description {
            font-size: 14px;
            color: #6B7280;
            margin: 0 0 20px 0;
            flex: 1;
        }

        .report-card-meta {
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding-top: 15px;
            border-top: 1px solid #E5E7EB;
        }

        .report-card-type {
            background-color: rgba(51, 51, 152, 0.1);
