        function createInfographicCanvas(id, data, type) {
            const canvas = document.createElement('canvas');
            canvas.width = 600;
            canvas.height = 400;
            const ctx = canvas.getContext('2d');

            // Fill background
            ctx.fillStyle = '#F9FAFB';
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            // Draw header
            ctx.fillStyle = '#333398';
            ctx.fillRect(0, 0, canvas.width, 60);

            // Draw logo/icon
            ctx.fillStyle = '#FFFFFF';
            ctx.beginPath();
            ctx.arc(40, 30, 20, 0, Math.PI * 2);
            ctx.fill();

            // Add title
            ctx.fillStyle = '#FFFFFF';
            ctx.font = 'bold 20px Poppins, sans-serif';
            ctx.textAlign = 'center';

            let title = '';
            switch(type) {
                case 'flow':
                    title = "Ghana's Oil Revenue Distribution";
                    break;
                case 'timeline':
                    title = "10 Years of Oil-Funded Development";
                    break;
                case 'map':
                    title = "Regional Distribution of Projects";
                    break;
                case 'funds':
                    title = "Ghana's Petroleum Funds Performance";
                    break;
            }

            ctx.fillText(title, canvas.width / 2, 35);

            // Draw content based on type
            if (type === 'flow') {
                drawPieChart(ctx, data, canvas.width, canvas.height);
            } else if (type === 'timeline') {
                drawTimeline(ctx, data, canvas.width, canvas.height);
            } else if (type === 'map') {
                drawMapChart(ctx, data, canvas.width, canvas.height);
            } else if (type === 'funds') {
                drawFundsChart(ctx, data, canvas.width, canvas.height);
            }

            // Add watermark
            ctx.fillStyle = 'rgba(0,0,0,0.1)';
            ctx.font = '12px Poppins, sans-serif';
            ctx.textAlign = 'right';
            ctx.fillText('© Ghana Oil Revenue Monitor 2024', canvas.width - 20, canvas.height - 15);

            // Apply to element
            const element = document.getElementById(id);
            element.style.backgroundImage = `url(${canvas.toDataURL()})`;
            element.style.backgroundSize = 'cover';
            element.style.backgroundPosition = 'center';

            // Store canvas data for preview
            element.dataset.canvasData = canvas.toDataURL();
        }

        function drawPieChart(ctx, data, width, height) {
            const centerX = width / 2;
            const centerY = height / 2;
            const radius = 120;

            let total = 0;
            data.forEach(item => {
                total += item.value;
            });

            let startAngle = 0;

            // Draw pie segments
            data.forEach(item => {
                const sliceAngle = 2 * Math.PI * item.value / total;

                ctx.fillStyle = item.color;
                ctx.beginPath();
                ctx.moveTo(centerX, centerY);
                ctx.arc(centerX, centerY, radius, startAngle, startAngle + sliceAngle);
                ctx.closePath();
                ctx.fill();

                // Draw labels
                const angleMiddle = startAngle + sliceAngle / 2;
                const labelX = centerX + (radius * 0.7) * Math.cos(angleMiddle);
                const labelY = centerY + (radius * 0.7) * Math.sin(angleMiddle);

                ctx.fillStyle = '#FFFFFF';
                ctx.font = 'bold 14px Poppins, sans-serif';
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillText(`${item.value}%`, labelX, labelY);

                startAngle += sliceAngle;
            });

            // Draw legend
            const legendX = width / 2 - 200;
            const legendY = height - 90;

            data.forEach((item, index) => {
                const itemY = legendY + index * 25;

                // Draw color box
                ctx.fillStyle = item.color;
                ctx.fillRect(legendX, itemY, 20, 20);

                // Draw label
                ctx.fillStyle = '#333333';
                ctx.font = '14px Poppins, sans-serif';
                ctx.textAlign = 'left';
                ctx.textBaseline = 'middle';
                ctx.fillText(item.label, legendX + 30, itemY + 10);
            });
        }

        function drawTimeline(ctx, data, width, height) {
            const timelineY = height / 2;
            const startX = 50;
            const endX = width - 50;
            const lineLength = endX - startX;
            const segmentWidth = lineLength / (data.length - 1);

            // Draw timeline line
            ctx.strokeStyle = '#CCCCCC';
            ctx.lineWidth = 4;
            ctx.beginPath();
            ctx.moveTo(startX, timelineY);
            ctx.lineTo(endX, timelineY);
            ctx.stroke();

            // Draw timeline points and labels
            data.forEach((item, index) => {
                const pointX = startX + segmentWidth * index;

                // Draw circle
                ctx.fillStyle = item.color;
                ctx.beginPath();
                ctx.arc(pointX, timelineY, 10, 0, Math.PI * 2);
                ctx.fill();

                // Draw year text above line
                ctx.fillStyle = '#333333';
                ctx.font = 'bold 16px Poppins, sans-serif';
                ctx.textAlign = 'center';
                ctx.fillText(item.year.toString(), pointX, timelineY - 30);

                // Draw title text below line
                ctx.fillStyle = '#555555';
                ctx.font = '14px Poppins, sans-serif';
                ctx.fillText(item.title, pointX, timelineY + 40);

                // Add connecting lines
                if (index < data.length - 1) {
                    const nextX = startX + segmentWidth * (index + 1);
                    ctx.strokeStyle = '#DDDDDD';
                    ctx.lineWidth = 2;
                    ctx.beginPath();
                    ctx.moveTo(pointX, timelineY);
                    ctx.lineTo(nextX, timelineY);
                    ctx.stroke();
                }
            });
        }

        function drawMapChart(ctx, data, width, height) {
            // Draw simplified Ghana map outline
            ctx.fillStyle = '#E6F3F7';
            ctx.fillRect(80, 100, 200, 220); // Simplified map shape

            ctx.strokeStyle = '#CCCCCC';
            ctx.lineWidth = 2;
            ctx.strokeRect(80, 100, 200, 220);

            // Draw region highlights
            const regionCoords = [
                {x: 180, y: 120, width: 60, height: 40}, // Greater Accra
                {x: 160, y: 170, width: 70, height: 50}, // Ashanti
                {x: 100, y: 200, width: 50, height: 70}, // Western
                {x: 140, y: 120, width: 50, height: 40}, // Northern
                {x: 190, y: 170, width: 60, height: 60}, // Eastern
            ];

            // Draw regions on map
            data.slice(0, 5).forEach((item, index) => {
                const region = regionCoords[index];
                ctx.fillStyle = item.color;
                ctx.fillRect(region.x, region.y, region.width, region.height);

                ctx.strokeStyle = '#FFFFFF';
                ctx.lineWidth = 1;
                ctx.strokeRect(region.x, region.y, region.width, region.height);
            });

            // Draw bar chart
            const barStartX = 320;
            const barWidth = 40;
            const barSpacing = 15;
            const maxBarHeight = 180;
            const barBottom = 320;

            const maxProjects = Math.max(...data.map(item => item.projects));

            data.forEach((item, index) => {
                const barHeight = (item.projects / maxProjects) * maxBarHeight;
                const barX = barStartX + index * (barWidth + barSpacing);
                const barY = barBottom - barHeight;

                // Draw bar
                ctx.fillStyle = item.color;
                ctx.fillRect(barX, barY, barWidth, barHeight);

                // Draw region label
                ctx.fillStyle = '#555555';
                ctx.font = '11px Poppins, sans-serif';
                ctx.textAlign = 'center';
                ctx.fillText(item.region.substring(0, 10), barX + barWidth / 2, barBottom + 20);

                // Draw value on bar
                ctx.fillStyle = '#333333';
                ctx.font = 'bold 14px Poppins, sans-serif';
                ctx.fillText(item.projects.toString(), barX + barWidth / 2, barY - 10);
            });

            // Draw legend title
            ctx.fillStyle = '#333333';
            ctx.font = 'bold 14px Poppins, sans-serif';
            ctx.textAlign = 'left';
            ctx.fillText('Number of Projects by Region', barStartX, 95);
        }

        function drawFundsChart(ctx, data, width, height) {
            const chartStartX = 70;
            const chartStartY = 100;
            const chartWidth = width - 140;
            const chartHeight = 200;
            const chartEndX = chartStartX + chartWidth;
            const chartEndY = chartStartY + chartHeight;

            // Draw axes
            ctx.strokeStyle = '#333333';
            ctx.lineWidth = 2;
            ctx.beginPath();
            ctx.moveTo(chartStartX, chartStartY);
            ctx.lineTo(chartStartX, chartEndY);
            ctx.lineTo(chartEndX, chartEndY);
            ctx.stroke();

            // Draw grid lines
            ctx.strokeStyle = '#EEEEEE';
            ctx.lineWidth = 1;

            // Horizontal grid lines
            const gridStep = chartHeight / 5;
            for (let i = 1; i <= 5; i++) {
                const y = chartEndY - i * gridStep;
                ctx.beginPath();
                ctx.moveTo(chartStartX, y);
                ctx.lineTo(chartEndX, y);
                ctx.stroke();

                // Draw y-axis labels
                ctx.fillStyle = '#666666';
                ctx.font = '12px Poppins, sans-serif';
                ctx.textAlign = 'right';
                ctx.fillText(`${i * 150}M`, chartStartX - 10, y + 5);
            }

            // Draw data lines
            const xStep = chartWidth / (data.length - 1);

            // Find max value for scaling
            const maxValue = Math.max(
                ...data.map(item => Math.max(item.stabilization, item.heritage))
            );

            // Draw stabilization fund line
            ctx.strokeStyle = '#333398';
            ctx.lineWidth = 3;
            ctx.beginPath();

            data.forEach((item, index) => {
                const x = chartStartX + index * xStep;
                const y = chartEndY - (item.stabilization / maxValue) * chartHeight;

                if (index === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }

                // Draw point
                ctx.fillStyle = '#333398';
                ctx.beginPath();
                ctx.arc(x, y, 5, 0, Math.PI * 2);
                ctx.fill();

                // Draw x-axis labels
                ctx.fillStyle = '#666666';
                ctx.font = '12px Poppins, sans-serif';
                ctx.textAlign = 'center';
                ctx.fillText(item.year.toString(), x, chartEndY + 20);
            });

            ctx.stroke();

            // Draw heritage fund line
            ctx.strokeStyle = '#ff9932';
            ctx.lineWidth = 3;
            ctx.beginPath();

            data.forEach((item, index) => {
                const x = chartStartX + index * xStep;
                const y = chartEndY - (item.heritage / maxValue) * chartHeight;

                if (index === 0) {
                    ctx.moveTo(x, y);
                } else {
                    ctx.lineTo(x, y);
                }

                // Draw point
                ctx.fillStyle = '#ff9932';
                ctx.beginPath();
                ctx.arc(x, y, 5, 0, Math.PI * 2);
                ctx.fill();
            });

            ctx.stroke();

            // Draw legend
            const legendY = chartEndY + 40;

            // Stabilization Fund
            ctx.fillStyle = '#333398';
            ctx.fillRect(chartStartX, legendY, 20, 10);

            ctx.fillStyle = '#333333';
            ctx.font = '14px Poppins, sans-serif';
            ctx.textAlign = 'left';
            ctx.fillText('Stabilization Fund', chartStartX + 30, legendY + 9);

            // Heritage Fund
            ctx.fillStyle = '#ff9932';
            ctx.fillRect(chartStartX + 180, legendY, 20, 10);

            ctx.fillStyle = '#333333';
            ctx.fillText('Heritage Fund', chartStartX + 210, legendY + 9);

            // Chart title
            ctx.fillStyle = '#333333';
            ctx.font = 'bold 16px Poppins, sans-serif';
            ctx.textAlign = 'center';
            ctx.fillText('Fund Performance (Million USD)', width / 2, 85);
        }

        function openPreview(infographicId) {
            const modal = document.getElementById('previewModal');
            const modalTitle = document.getElementById('modalTitle');
            const modalBody = document.getElementById('modalBody');
            const modalDownloadBtn = document.getElementById('modalDownloadBtn');

            // Get infographic element
            const infographic = document.getElementById(infographicId);
            const title = infographic.nextElementSibling.querySelector('.infographic-title').textContent;

            // Set modal title
            modalTitle.textContent = title;

            // Create and add image to modal body
            modalBody.innerHTML = '';
            const img = document.createElement('img');
            img.src = infographic.dataset.canvasData;
            img.className = 'infographic-preview';
            img.alt = title;
            modalBody.appendChild(img);

            // Show modal
            modal.style.display = 'flex';

            // Prevent body scrolling
            document.body.style.overflow = 'hidden';
        }

        function closePreview() {
            const modal = document.getElementById('previewModal');
            modal.style.display = 'none';

            // Restore body scrolling
            document.body.style.overflow = '';
        }

        // Close modal when clicking outside content
        window.onclick = function(event) {
            const modal = document.getElementById('previewModal');
            if (event.target === modal) {
                closePreview();
            }
        }


